SELECT material_id, COUNT(request_id) AS request_count
FROM material_requests
GROUP BY material_id;

SELECT request_id, justification
FROM material_requests
WHERE approval_status = 'pending';

SELECT SUM(quantity) AS total_pending_requests
FROM material_requests
WHERE approval_status = 'pending';

SELECT DISTINCT material_id
FROM audit_log
WHERE log_type = 'usage';

SELECT COUNT(*) AS total_material_usage_records
FROM material_usage
WHERE quantity > 0;

SELECT SUM(quantity_required) AS total_quantity_required
FROM product_components
WHERE material_id = 1;
